SELECT id, username, nickname, avatar, phone, email, student_no, role, grade, major, status, create_time, update_time FROM sys_user
AND (username LIKE CONCAT('%', #{keyword}, '%') OR nickname LIKE CONCAT('%', #{keyword}, '%') OR student_no LIKE CONCAT('%', #{keyword}, '%'))
AND role = #{role}
AND status = #{status}
ORDER BY create_time DESC
